"""
Mini4wd EXE Builder
start.bat を起動する exe を GUI で作成するツール
"""
import os, sys, subprocess, threading, shutil, tempfile, base64
import tkinter as tk
from tkinter import ttk, messagebox, filedialog


def _known_folder_path(folderid_guid):
    """Windowsの既知フォルダー実パスを取得（OneDriveリダイレクト対応）。失敗時はNone。"""
    try:
        import ctypes
        _CoTaskMemFree = ctypes.windll.ole32.CoTaskMemFree
        _SHGetKnownFolderPath = ctypes.windll.shell32.SHGetKnownFolderPath
        _CLSIDFromString = ctypes.windll.ole32.CLSIDFromString
        guid = ctypes.create_string_buffer(16)
        if _CLSIDFromString(ctypes.c_wchar_p(folderid_guid), guid) != 0:
            return None
        ptr = ctypes.c_wchar_p()
        if _SHGetKnownFolderPath(guid, 0, None, ctypes.byref(ptr)) != 0:
            return None
        path = ptr.value
        _CoTaskMemFree(ptr)
        return path
    except Exception:
        return None


def _get_desktop_dir():
    # FOLDERID_Desktop {B4BFCC3A-DB2C-424C-B029-7FE99A87C641}
    p = _known_folder_path("{B4BFCC3A-DB2C-424C-B029-7FE99A87C641}")
    if p and os.path.isdir(p):
        return p
    return os.path.join(os.path.expanduser("~"), "Desktop")


SETUP_DIR = os.path.dirname(os.path.abspath(__file__))
BASE_DIR  = os.path.dirname(SETUP_DIR)
VENV_PY   = os.path.join(BASE_DIR, "venv", "Scripts", "python.exe")
EXE_NAME  = "Mini4wd"
PREVIEW_W = 100

DEFAULT_IMG_B64 = ""
DEFAULT_ICO_B64 = ""

LAUNCHER_CODE = (
    "import os, sys, subprocess\n"
    "SHOW_CONSOLE = True  # コンソール表示=True / 非表示に戻す=False (変更後は再ビルド)\n"
    "base = os.path.dirname(sys.executable) if getattr(sys,'frozen',False)"
    " else os.path.dirname(os.path.abspath(__file__))\n"
    "bat = os.path.join(base, 'start', 'start.bat')\n"
    "if not os.path.exists(bat):\n"
    "    import ctypes\n"
    "    ctypes.windll.user32.MessageBoxW(0,'start.bat not found:\\n'+bat,'Mini4WD Race System',0x10)\n"
    "    sys.exit(1)\n"
    "flags = subprocess.CREATE_NEW_CONSOLE if SHOW_CONSOLE else subprocess.CREATE_NO_WINDOW\n"
    "subprocess.Popen(['cmd.exe', '/c', bat], cwd=os.path.dirname(bat), creationflags=flags)\n"
)

# 観覧用ランチャー（ブラウザで /view/ を開くだけ）。os.startfile は既定ブラウザで
# URL を開く Windows 専用API。--noconsole でも安全に動く。
VIEW_LOCAL_CODE = (
    "import os\n"
    "os.startfile('http://localhost:8000/view/')\n"
)

def _view_remote_code(ip):
    return (
        "import os\n"
        "os.startfile('http://" + ip + ":8000/view/')\n"
    )


def _extract_default_file(b64data, filename):
    path = os.path.join(tempfile.gettempdir(), filename)
    if not os.path.exists(path):
        with open(path, "wb") as f:
            f.write(base64.b64decode(b64data))
    return path


class App(tk.Tk):
    def __init__(self):
        super().__init__()
        self.title("Mini4wd EXE Builder")
        self.resizable(False, False)
        self._header_photo = None
        # フォント統一（Yu Gothic UI → Meiryo UI → MS UI Gothic）
        from tkinter import font as tkfont
        default_font = tkfont.nametofont("TkDefaultFont")
        default_font.configure(family="Yu Gothic UI", size=10)
        self.option_add("*Font", default_font)
        self._build_ui()
        self._refresh_header()
        self._check_ready()

    def _build_ui(self):
        tk.Label(
            self, text="起動用アイコンを設定します",
            font=("Yu Gothic UI", 12, "bold"), fg="#222", pady=8,
        ).pack()

        self.header_frame = tk.Frame(self, width=PREVIEW_W, height=PREVIEW_W, bg="#111")
        self.header_frame.pack_propagate(False)
        self.header_frame.pack()

        self.header_label = tk.Label(self.header_frame, bg="#111")
        self.header_label.place(relx=0.5, rely=0.5, anchor="center")

        cfg = tk.Frame(self, padx=16, pady=8)
        cfg.pack(fill="x")

        tk.Label(cfg, text="ヘッダー", font=("Yu Gothic UI", 9, "bold"),
                 anchor="w").grid(row=0, column=0, columnspan=3, sticky="w", pady=(0, 2))

        self.header_mode = tk.StringVar(value="image")
        tk.Radiobutton(cfg, text="画像ファイル", variable=self.header_mode, value="image",
                       command=self._on_header_mode).grid(row=1, column=0, sticky="w")
        tk.Radiobutton(cfg, text="テキスト", variable=self.header_mode, value="text",
                       command=self._on_header_mode).grid(row=1, column=1, sticky="w")

        self.img_path = tk.StringVar()
        self.img_entry = ttk.Entry(cfg, textvariable=self.img_path, width=38)
        self.img_entry.grid(row=2, column=0, columnspan=2, sticky="ew", pady=2)
        self.img_browse = ttk.Button(cfg, text="参照...", width=8, command=self._browse_header_img)
        self.img_browse.grid(row=2, column=2, padx=(6, 0), pady=2)

        self.header_text = tk.StringVar(value="Mini4wd EXE Builder")
        self.text_entry = ttk.Entry(cfg, textvariable=self.header_text, width=38, state="disabled")
        self.text_entry.grid(row=3, column=0, columnspan=3, sticky="ew", pady=2)
        self.header_text.trace_add("write", lambda *_: self._refresh_header())
        self.img_path.trace_add("write", lambda *_: self._refresh_header())

        ttk.Separator(cfg).grid(row=4, column=0, columnspan=3, sticky="ew", pady=8)

        tk.Label(cfg, text="アイコン", font=("Yu Gothic UI", 9, "bold"),
                 anchor="w").grid(row=5, column=0, columnspan=3, sticky="w", pady=(0, 2))

        self.use_icon = tk.BooleanVar(value=True)
        ttk.Checkbutton(cfg, text="ICO ファイルを使用する", variable=self.use_icon,
                        command=self._on_toggle_icon).grid(row=6, column=0, columnspan=3, sticky="w")

        self.ico_path = tk.StringVar()
        self.ico_entry = ttk.Entry(cfg, textvariable=self.ico_path, width=38)
        self.ico_entry.grid(row=7, column=0, columnspan=2, sticky="ew", pady=2)
        self.ico_browse = ttk.Button(cfg, text="参照...", width=8, command=self._browse_ico)
        self.ico_browse.grid(row=7, column=2, padx=(6, 0), pady=2)

        cfg.columnconfigure(0, weight=1)
        ttk.Separator(self).pack(fill="x", padx=16, pady=4)

        self.btn = tk.Button(
            self, text="起動用アイコンを作成", command=self._start_build,
            font=("Yu Gothic UI", 13, "bold"), bg="#0078d4", fg="white",
            activebackground="#005a9e", activeforeground="white",
            relief="flat", padx=24, pady=12, cursor="hand2",
        )
        self.btn.pack(pady=12, ipadx=16)

        self.log = tk.Text(self, width=62, height=12,
                           font=("Consolas", 8), bg="#1e1e1e", fg="#d4d4d4",
                           state="disabled", relief="flat")
        self.log.pack(padx=16, pady=(0, 16))
        self.log.tag_config("ok",  foreground="#4ec94e")
        self.log.tag_config("err", foreground="#f44")
        self.log.tag_config("inf", foreground="#4af")

    def _on_header_mode(self):
        if self.header_mode.get() == "image":
            self.img_entry.config(state="normal")
            self.img_browse.config(state="normal")
            self.text_entry.config(state="disabled")
        else:
            self.img_entry.config(state="disabled")
            self.img_browse.config(state="disabled")
            self.text_entry.config(state="normal")
        self._refresh_header()

    def _browse_header_img(self):
        path = filedialog.askopenfilename(
            title="ヘッダー画像を選択",
            filetypes=[("画像ファイル", "*.jpg *.jpeg *.png *.bmp *.gif"),
                       ("すべてのファイル", "*.*")],
            initialdir=BASE_DIR,
        )
        if path:
            self.img_path.set(path)

    def _refresh_header(self):
        if self.header_mode.get() == "image":
            path = self.img_path.get().strip()
            if not path or not os.path.exists(path):
                path = _extract_default_file(DEFAULT_IMG_B64, "mini4wd_default.jpg")
            try:
                from PIL import Image, ImageTk
                img = Image.open(path)
                w, h = img.size
                if w > PREVIEW_W:
                    h = int(h * PREVIEW_W / w)
                    w = PREVIEW_W
                img = img.resize((w, h), Image.LANCZOS)
                self._header_photo = ImageTk.PhotoImage(img)
                self.header_frame.config(width=w, height=h)
                self.header_label.config(image=self._header_photo, text="")
            except Exception as e:
                self.header_label.config(image="", text="画像エラー: " + str(e),
                                         fg="red", font=("Yu Gothic UI", 9))
        else:
            txt = self.header_text.get() or "Mini4wd EXE Builder"
            self.header_frame.config(width=PREVIEW_W, height=PREVIEW_W)
            self.header_label.config(image="", text=txt,
                                     fg="white", font=("Yu Gothic UI", 16, "bold"))

    def _on_toggle_icon(self):
        state = "normal" if self.use_icon.get() else "disabled"
        self.ico_entry.config(state=state)
        self.ico_browse.config(state=state)

    def _browse_ico(self):
        path = filedialog.askopenfilename(
            title="ICO ファイルを選択",
            filetypes=[("ICO ファイル", "*.ico"), ("すべてのファイル", "*.*")],
            initialdir=BASE_DIR,
        )
        if path:
            self.ico_path.set(path)

    def _check_ready(self):
        if not os.path.exists(VENV_PY):
            self.btn.config(state="disabled")
            self._log("[ERROR] venv が見つかりません。初回セットアップ・レストア用.bat を実行してください。", "err")
        else:
            self._log("venv : OK", "ok")
            self._log("出力先: " + BASE_DIR, "inf")

    def _log(self, msg, tag=None):
        self.log.config(state="normal")
        self.log.insert("end", msg + "\n", tag or "")
        self.log.see("end")
        self.log.config(state="disabled")
        self.update_idletasks()

    def _start_build(self):
        self.btn.config(state="disabled")
        threading.Thread(target=self._build, daemon=True).start()

    def _build(self):
        try:
            self._log("PyInstaller をインストール中...", "inf")
            r = subprocess.run(
                [VENV_PY, "-m", "pip", "install", "pyinstaller", "-q"],
                capture_output=True, text=True)
            if r.returncode != 0:
                self._log(r.stderr or "pip failed", "err")
                return
            self._log("  [OK]", "ok")

            self._log("EXE をビルド中...", "inf")
            tmp = tempfile.mkdtemp(prefix="mini4wd_build_")
            launcher_py = os.path.join(tmp, "_launcher.py")
            with open(launcher_py, "w", encoding="utf-8") as lf:
                lf.write(LAUNCHER_CODE)

            ico_specified = self.ico_path.get().strip()
            if ico_specified and os.path.exists(ico_specified):
                ico = ico_specified
            else:
                ico = _extract_default_file(DEFAULT_ICO_B64, "mini4wd_default.ico")

            cmd = [
                VENV_PY, "-m", "PyInstaller",
                "--onefile", "--noconsole",
                "--name", EXE_NAME,
                "--distpath", BASE_DIR,
                "--workpath", tmp,
                "--specpath", tmp,
                "--icon", ico,
            ]
            self._log("  icon: " + os.path.basename(ico), "inf")
            cmd.append(launcher_py)

            proc = subprocess.Popen(
                cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                text=True, encoding="utf-8", errors="replace")
            for line in proc.stdout:
                line = line.rstrip()
                if line:
                    self._log(line, "err" if "ERROR" in line.upper() else None)
            proc.wait()

            shutil.rmtree(tmp, ignore_errors=True)

            img_specified = self.img_path.get().strip()
            if img_specified and os.path.exists(img_specified):
                _src = img_specified
            else:
                _src = _extract_default_file(DEFAULT_IMG_B64, "mini4wd_default.jpg")

            _dst_dir = os.path.join(BASE_DIR, "app", "static")
            if os.path.isdir(_dst_dir):
                import shutil as _sh
                _dst = os.path.join(_dst_dir, "logo_header.jpg")
                try:
                    _sh.copy2(_src, _dst)
                    self._log("  logo → " + _dst, "ok")
                except Exception as _e:
                    self._log("  logo copy failed: " + str(_e), "err")

            exe_path = os.path.join(BASE_DIR, EXE_NAME + ".exe")
            if proc.returncode == 0 and os.path.exists(exe_path):
                # 観覧用EXE（親機=localhost / 子機=親機IP）を追加ビルド
                import socket as _sock
                try:
                    _ip = _sock.gethostbyname(_sock.gethostname())
                except Exception:
                    _ip = "127.0.0.1"
                self._log("観覧用EXE をビルド中（親機/子機）...", "inf")
                view_local = self._build_extra_exe(
                    VIEW_LOCAL_CODE, "Mini4WDViewLocal", "Mini4WD観覧親機", ico)
                view_remote = self._build_extra_exe(
                    _view_remote_code(_ip), "Mini4WDViewRemote", "Mini4WD観覧子機", ico)
                if view_local:
                    self._log("  [OK] " + view_local + "  (http://localhost:8000/view/)", "ok")
                else:
                    self._log("  [WARN] 観覧親機EXE のビルドに失敗しました。", "err")
                if view_remote:
                    self._log("  [OK] " + view_remote + "  (http://" + _ip + ":8000/view/)", "ok")
                else:
                    self._log("  [WARN] 観覧子機EXE のビルドに失敗しました。", "err")
                self._create_shortcuts(exe_path, ico, view_local, view_remote)
                self._log("\n完了: " + exe_path, "ok")
                messagebox.showinfo(
                    "完了",
                    "Mini4wd.exe と観覧用EXE（親機/子機）を作成しました。\n\n"
                    "デスクトップに「Mini4WD起動用」「Mini4WD観覧親機」\n"
                    "「Mini4WD観覧子機」ショートカットを作成しました。",
                )
                self.destroy()
            else:
                self._log("\n[ERROR] ビルドに失敗しました。", "err")

        except Exception as e:
            self._log("[ERROR] " + str(e), "err")
        finally:
            if self.winfo_exists():
                self.btn.config(state="normal")

    def _build_extra_exe(self, launcher_code, build_name, final_name, ico):
        """ASCII の build_name でビルドし、final_name(.exe) へリネームして返す。
        （日本語名を PyInstaller に直接渡すと失敗しやすいための回避）。失敗時 None。"""
        tmp = tempfile.mkdtemp(prefix="mini4wd_build_")
        try:
            lp = os.path.join(tmp, "_launcher.py")
            with open(lp, "w", encoding="utf-8") as f:
                f.write(launcher_code)
            cmd = [
                VENV_PY, "-m", "PyInstaller",
                "--onefile", "--noconsole",
                "--name", build_name,
                "--distpath", BASE_DIR,
                "--workpath", tmp,
                "--specpath", tmp,
                "--icon", ico,
                lp,
            ]
            proc = subprocess.Popen(
                cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                text=True, encoding="utf-8", errors="replace")
            for line in proc.stdout:
                line = line.rstrip()
                if line and "ERROR" in line.upper():
                    self._log(line, "err")
            proc.wait()
            built = os.path.join(BASE_DIR, build_name + ".exe")
            if proc.returncode != 0 or not os.path.exists(built):
                return None
            final = os.path.join(BASE_DIR, final_name + ".exe")
            try:
                if os.path.exists(final):
                    os.remove(final)
                os.replace(built, final)
            except Exception as e:
                self._log("  リネーム失敗(" + final_name + "): " + str(e), "err")
                return None
            return final
        finally:
            shutil.rmtree(tmp, ignore_errors=True)

    def _create_shortcuts(self, exe_path, ico, view_local=None, view_remote=None):
        desktop = _get_desktop_dir()

        def _make_lnk(name, target):
            lnk_path = os.path.join(desktop, name + ".lnk")
            icon_stmt = ("$s.IconLocation = '" + ico + "';") if ico and os.path.exists(ico) else ""
            ps_script = (
                "$ws = New-Object -ComObject WScript.Shell;"
                "$s = $ws.CreateShortcut('" + lnk_path + "');"
                "$s.TargetPath = '" + target + "';"
                "$s.WorkingDirectory = '" + os.path.dirname(target) + "';"
                + icon_stmt +
                "$s.Save()"
            )
            r = subprocess.run(
                ["powershell", "-NoProfile", "-Command", ps_script],
                capture_output=True, text=True)
            if r.returncode == 0:
                self._log("  ショートカット作成: " + lnk_path, "ok")
            else:
                self._log("  [WARN] ショートカット作成失敗(" + name + "): " + (r.stderr or ""), "err")

        # 起動用（サーバー起動）
        try:
            _make_lnk("Mini4WD起動用", exe_path)
        except Exception as e:
            self._log("  [WARN] 起動用ショートカット作成失敗: " + str(e), "err")

        # 観覧親機（localhost）
        if view_local and os.path.exists(view_local):
            try:
                _make_lnk("Mini4WD観覧親機", view_local)
            except Exception as e:
                self._log("  [WARN] 観覧親機ショートカット作成失敗: " + str(e), "err")

        # 観覧子機（親機IP）
        if view_remote and os.path.exists(view_remote):
            try:
                _make_lnk("Mini4WD観覧子機", view_remote)
            except Exception as e:
                self._log("  [WARN] 観覧子機ショートカット作成失敗: " + str(e), "err")

        # 旧「Mini4WD観覧用.url」が残っていれば掃除（新方式のEXEショートカットへ置換）
        try:
            old_url = os.path.join(desktop, "Mini4WD観覧用.url")
            if os.path.exists(old_url):
                os.remove(old_url)
                self._log("  旧 観覧用.url を削除しました。", "inf")
        except Exception:
            pass



if __name__ == "__main__":
    app = App()
    app.mainloop()
